import { 
  useEffect,
  createContext
} from 'react'

import { useRadioGroup } from 'react-aria'
import { useRadioGroupState } from 'react-stately'

import {
  Description,
  Label
} from '../../base'

/**
 * <RadioGroup label="Radio label">
 *   <Radio value="2">Value 1</Radio>
 *   <Radio value="1">Value 2</Radio>
 * </RadioGroup>
 * 
 * @see https://react-spectrum.adobe.com/react-aria/useRadioGroup.html
 */

const RadioContext = createContext(null)

const RadioGroup = props => {

  const state = useRadioGroupState(props)

  const {
    radioGroupProps,
    labelProps,
    descriptionProps
  } = useRadioGroup(props, state)

  useEffect(() => {
    props.onChange && props.onChange(state.selectedValue)
  }, [state.selectedValue])

  return(
    <div className="tf-radio-group">
      { props.label &&
        <Label labelProps={ labelProps } parent={ props }>
          { props.label }
        </Label> }
      <div className="tf-radio-group-container" { ...radioGroupProps }>
        <RadioContext.Provider value={ state }>
          { props.children }
        </RadioContext.Provider>
      </div>
      { props.description &&
        <Description descriptionProps={ descriptionProps } parent={ props }>
          { props.description }
        </Description> }
    </div>
  )
}

export {
  RadioGroup,
  RadioContext
}

import {
  useContext,
  useRef
} from 'react'

import { RadioContext } from './RadioGroup'
import { useRadio } from 'react-aria'

const Radio = props => {

  const state = useContext(RadioContext)
  const ref = useRef(null)

  const { inputProps } = useRadio(props, state, ref)

  return (
    <label className="tf-radio">
      <input {...inputProps} ref={ref} />
      { props.children }
    </label>
  )
}

export default Radio

import { 
